    ('Полигон ТБО Нарынской области',    'MUNICIPAL', 'Нарынская',   'Нарынская обл.',                                           41.9190::double precision, 74.5264::double precision, 'ACTIVE', NULL),
    ('Полигон ТБО Ноокатского района',   'MUNICIPAL', 'Ошская',      'Ошская обл., Ноокатский район',                            40.2439::double precision, 71.4636::double precision, 'ACTIVE', NULL),
