    ('Хвостохранилище ОАО «Кадамжайский сурьмяный комбинат» (КСК)', 'HAZARDOUS', 'Баткенская', 'Баткенская обл., Кадамжайский район', 40.1486::double precision, 71.7089::double precision, 'ACTIVE', 'ОАО «Кадамжайский сурьмяный комбинат»'),
    ('Отвал «Давыдов» (м-ние Кумтор)',   'HAZARDOUS', 'Иссык-Кульская', 'Иссык-Кульская обл., р-н м-ния Кумтор',                 41.8653::double precision, 78.1612::double precision, 'ACTIVE', 'ЗАО «Кумтор Голд Компани»'),
    ('Отвал «Сары-Төр» (м-ние Кумтор)',  'HAZARDOUS', 'Иссык-Кульская', 'Иссык-Кульская обл., р-н м-ния Кумтор',                 41.8506::double precision, 78.1561::double precision, 'ACTIVE', 'ЗАО «Кумтор Голд Компани»'),
