-- ─────────────────────────────────────────────────────────────────────────
-- 2. НЕСАНКЦИОНИРОВАННЫЕ СВАЛКИ (5 объектов)
-- status: ACTIVE | REMEDIATED | MONITORED
-- Данные предварительные, по публикациям СМИ — требуют верификации.
-- ─────────────────────────────────────────────────────────────────────────
INSERT INTO dumps (name, region, address, latitude, longitude, waste_types, status, notes)
SELECT * FROM (VALUES
    ('Стихийная свалка по р. Аламедин',            'Чуйская',         'Чуйская обл., пойма р. Аламедин, р-н с. Лебединовка', 42.9456::double precision, 74.5123::double precision, ARRAY['Бытовые отходы','Строительный мусор']::text[], 'ACTIVE', 'Бытовые и строительные отходы. Данные требуют верификации.'),
    ('Стихийная свалка у г. Токмок',               'Чуйская',         'Чуйская обл., окрестности г. Токмок',                 42.8567::double precision, 75.3123::double precision, ARRAY['Бытовые отходы']::text[],                         'ACTIVE', 'Крупная стихийная свалка. Данные требуют верификации.'),
    ('Свалка на трассе Бишкек-Ош (км 45)',         'Чуйская',         'Чуйская обл., трасса Бишкек-Ош, 45-й км',              42.6234::double precision, 74.3567::double precision, ARRAY['Пластик','Строительный мусор']::text[],           'ACTIVE', 'Пластик и строительный мусор. Данные требуют верификации.'),
    ('Стихийная свалка у г. Майлуу-Суу',           'Джалал-Абадская', 'Джалал-Абадская обл., г. Майлуу-Суу',                   41.2623::double precision, 72.4512::double precision, ARRAY['Бытовые отходы','Промышленные']::text[],         'MONITORED', 'Район исторических урановых хранилищ. Данные требуют верификации.'),
    ('Свалка в пригороде г. Ош',                   'Ошская',          'Ошская обл., Кара-Сууйский район',                      40.4812::double precision, 72.6789::double precision, ARRAY['Смешанные отходы']::text[],                        'ACTIVE', 'Смешанные отходы рядом с жилмассивом. Данные требуют верификации.')
) AS t(name, region, address, latitude, longitude, waste_types, status, notes)
WHERE NOT EXISTS (SELECT 1 FROM dumps LIMIT 1);


