-- ─────────────────────────────────────────────────────────────────────────
-- 4. ПЕРЕРАБОТЧИКИ (8 объектов)
-- status: ACTIVE | SUSPENDED | INACTIVE
-- ИНН с пометкой «требует уточнения» — заполняется в ЛК сотрудника после
-- сверки в реестре МЭК КР / ГНС. Уникальность гарантирована временными ID.
-- ─────────────────────────────────────────────────────────────────────────
INSERT INTO recyclers (company_name, legal_form, inn, region, address, latitude, longitude, status, notes)
SELECT * FROM (VALUES
    ('ОсОО «Триод» (приём лома металлов)', 'ОсОО', '00000000000081', 'Бишкек',   'г. Бишкек, ул. 7 апреля, 7', 42.8710::double precision, 74.5920::double precision, 'ACTIVE', 'Заготовка, переработка и реализация лома цветных и чёрных металлов. ИНН требует уточнения.'),
    ('ОсОО «Фер-Таш»',                      'ОсОО', '00000000000082', 'Бишкек',   'г. Бишкек',                  42.8642::double precision, 74.6275::double precision, 'ACTIVE', 'Данные требуют актуализации оператором.'),
    ('Комбинат Коммунальных Предприятий (Токмок)', 'ГП', '00000000000083', 'Чуйская', 'Чуйская обл., г. Токмок', 42.8393::double precision, 75.2887::double precision, 'ACTIVE', 'Коммунальное предприятие г. Токмок.'),
    ('Центр раздельного сбора (Кант)',      'ОсОО', '00000000000084', 'Чуйская', 'Чуйская обл., г. Кант',      42.8934::double precision, 74.8954::double precision, 'ACTIVE', 'Полный цикл: ПЭТ, алюминий, стекло, картон, бумага, пластик, текстиль, электроника.'),
    ('«Кара-металл алуу борбору» (чёрный металл)', 'ОсОО', '00000000000085', 'Бишкек', 'г. Бишкек', 42.8519::double precision, 74.5433::double precision, 'ACTIVE', 'Центр приёма чёрного металла. Данные требуют актуализации.'),
    ('«Чёрный Металл» (центр приёма)',      'ОсОО', '00000000000086', 'Бишкек',   'г. Бишкек',                  42.8520::double precision, 74.5489::double precision, 'ACTIVE', 'Центр приёма чёрного металла. Данные требуют актуализации.'),
    ('Пункт приёма металлолома (Бишкек, ул. Дэн Сяопина)', 'ОсОО', '00000000000087', 'Бишкек', 'г. Бишкек, ул. Дэн Сяопина', 42.8519::double precision, 74.5521::double precision, 'ACTIVE', 'Данные требуют актуализации.'),
    ('ОсОО «Organic» (Кант)',               'ОсОО', '00000000000088', 'Чуйская', 'Чуйская обл., г. Кант',      42.8917::double precision, 74.8601::double precision, 'ACTIVE', 'Приём ПЭТ и стеклотары. Данные требуют актуализации.')
